@spec mm_addressing_spec  src=tests/specs/mm_addressing_spec.lua  loc=144  sha=37ed80d  cases=7
@exercises midiManager (h.fm)
@surface   fm:notes, fm:byUuid, fm:ccs, fm:reload, fm:modify, fm:assign
@harness   mk{seed.notes}, bareMM

# Intent
  Pin-tests for how midiManager is addressed. Every event mm hands out carries a
  uuid, and that uuid is the handle: byUuid, assign and delete all take one.
  
  Content keys (evType, chan, ppq, pitch|cc) stay private to mm, where they serve
  only the same-pitch collision backstop -- see mm_collision_backstop_spec.
  
  Identity contract:
    * Every event has one, minted at add or at load.
    * Stable under every assign: moving ppq, pitch or chan does not re-key it.
    * Durable across reload, except a plain cc -- it binds no sidecar, so its uuid
      is in-memory only and re-minted each load. See mm_plain_cc_spec.

# Cases
  @case 'note: a fetched event round-trips through byUuid'  [harness]  @ 17-30
  @case 'cc: a plain cc is addressable like any other'  [harness]  @ 34-43
  @case 'pb / pa / at / pc: every evType yields a working handle'  [harness]  @ 47-66
  @case 'a persisted note keeps its handle across reload'  [harness]  @ 70-83
  @case 'moving an identity field does not re-key: the same handle resolves to the moved note'  [harness]  @ 87-103
  @case 'distinct events get distinct handles'  [harness]  @ 107-131
  @case 'byUuid returns nil for an unknown handle'  [harness]  @ 135-142

# Uses (outbound edges)
  @use call fm:notes  @ 22,75,92,101,122
  @use call fm:byUuid  @ 24,38,59,80,97,140,141
  @use call fm:ccs  @ 37,58,123
  @use call fm:reload  @ 78
  @use call fm:modify  @ 95
  @use call fm:assign  @ 95

